1	// claim-office.ts
2	//
3	// Design choices for the input shape (documented for future tests):
4	// - quote(input) takes an object with `customer` and `items`.
5	//   - customer: { yearsWithMHPCO: number, isFollowUpContract: boolean }
6	//     - yearsWithMHPCO: how long the customer has been with MHPCO (drives loyalty discount).
7	//     - isFollowUpContract: whether this quote is the customer's second/follow-up
8	//       contract in the scenario (drives the 15% follow-up discount).
9	//   - items: an array of items to be insured. Empty array means no items.
10	// - quote returns the premium in G as a number.
11	// - claim is also exported (per the spec import) but not yet implemented.
12	
13	export type Customer = {
14	  yearsWithMHPCO: number;
15	  isFollowUpContract: boolean;
16	};
17	
18	export type Item = {
19	  type: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
20	  cursed?: boolean;
21	  enchantment?: number;
22	  material?: string;
23	};
24	
25	export type QuoteInput = {
26	  customer: Customer;
27	  items: Item[];
28	};
29	
30	// Flat fee added to every quote at the very end (spec: "processing fee of 5 G").
31	// Currently observed in the empty-list test (premium = fee only).
32	const PROCESSING_FEE = 5;
33	
34	// Block-of-3 discount: when items are exactly 3 of the same type,
35	// the policy base premium for that group is a flat 60 G.
36	const BLOCK_SIZE = 3;
37	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
38	
39	// Base premium per item type, in G (before any modifiers or fees).
40	// Keyed by Item["type"] so adding a new item variant is caught at compile time
41	// (the Record will require a corresponding entry).
42	const BASE_PREMIUM_BY_TYPE: Record<Item["type"], number> = {
43	  sword: 100,
44	  amulet: 60,
45	  staff: 80,
46	  potion: 40,
47	  rune: 25,
48	  moonstone: 25,
49	};
50	
51	// Modifier rates expressed as numerator/denominator to avoid floating-point error
52	// for the integer-and-half cases under test (e.g. 100 * 1.1 ≠ 110 in IEEE-754).
53	//
54	// Item-level surcharges (applied to a single item's base premium):
55	const CURSED_SURCHARGE_NUM = 1;
56	const CURSED_SURCHARGE_DEN = 2; // +50%
57	const HIGH_ENCHANTMENT_SURCHARGE_NUM = 3;
58	const HIGH_ENCHANTMENT_SURCHARGE_DEN = 10; // +30%
59	const HIGH_ENCHANTMENT_THRESHOLD = 5;
60	//
61	// Policy-level modifiers (applied to the policy base premium):
62	const FIRST_INSURANCE_NUM = 1;
63	const FIRST_INSURANCE_DEN = 10; // +10%
64	const LOYALTY_DISCOUNT_NUM = 1;
65	const LOYALTY_DISCOUNT_DEN = 5; // -20%
66	const LOYALTY_THRESHOLD_YEARS = 2;
67	const FOLLOW_UP_DISCOUNT_NUM = 15;
68	const FOLLOW_UP_DISCOUNT_DEN = 100; // -15%
69	
70	// Component types eligible for the block-of-3 discount.
71	const COMPONENT_TYPES: ReadonlySet<Item["type"]> = new Set(["rune", "moonstone"]);
72	
73	function isComponent(item: Item): boolean {
74	  return COMPONENT_TYPES.has(item.type);
75	}
76	
77	function itemBaseOnly(item: Item): number {
78	  return BASE_PREMIUM_BY_TYPE[item.type];
79	}
80	
81	function itemSurcharges(item: Item): number {
82	  const base = BASE_PREMIUM_BY_TYPE[item.type];
83	  let surcharge = 0;
84	  if (item.cursed) {
85	    surcharge += (base * CURSED_SURCHARGE_NUM) / CURSED_SURCHARGE_DEN;
86	  }
87	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
88	    surcharge += (base * HIGH_ENCHANTMENT_SURCHARGE_NUM) / HIGH_ENCHANTMENT_SURCHARGE_DEN;
89	  }
90	  return surcharge;
91	}
92	
93	function groupBaseSum(items: Item[]): number {
94	  return items.reduce((sum, item) => sum + itemBaseOnly(item), 0);
95	}
96	
97	function groupByType(items: Item[]): Map<Item["type"], Item[]> {
98	  const groups = new Map<Item["type"], Item[]>();
99	  for (const item of items) {
100	    const group = groups.get(item.type) ?? [];
101	    group.push(item);
102	    groups.set(item.type, group);
103	  }
104	  return groups;
105	}
106	
107	function groupBasePremium(group: Item[]): number {
108	  if (group.length === BLOCK_SIZE && isComponent(group[0])) {
109	    return BLOCK_OF_THREE_BASE_PREMIUM;
110	  }
111	  return groupBaseSum(group);
112	}
113	
114	function policyBasePremium(items: Item[]): number {
115	  const groups = groupByType(items);
116	  return Array.from(groups.values()).reduce(
117	    (total, group) => total + groupBasePremium(group),
118	    0,
119	  );
120	}
121	
122	function totalItemSurcharges(items: Item[]): number {
123	  return items.reduce((sum, item) => sum + itemSurcharges(item), 0);
124	}
125	
126	export function quote(input: QuoteInput): number {
127	  // policyBase = sum of base premiums (with block-of-3 for components)
128	  // itemSurcharges = curse + high enchantment, each on item base only
129	  // firstInsurance = 10% of policyBase
130	  // loyalty = 20% of policyBase if 2+ years
131	  // followUp = 15% of policyBase if follow-up contract
132	  // total = policyBase + itemSurcharges + firstInsurance - loyalty - followUp + 5
133	  const { customer, items } = input;
134	  const policyBase = policyBasePremium(items);
135	  const surcharges = totalItemSurcharges(items);
136	  const firstInsurance = (policyBase * FIRST_INSURANCE_NUM) / FIRST_INSURANCE_DEN;
137	  const loyalty = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
138	    ? (policyBase * LOYALTY_DISCOUNT_NUM) / LOYALTY_DISCOUNT_DEN
139	    : 0;
140	  const followUp = customer.isFollowUpContract
141	    ? (policyBase * FOLLOW_UP_DISCOUNT_NUM) / FOLLOW_UP_DISCOUNT_DEN
142	    : 0;
143	  return Math.ceil(policyBase + surcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE);
144	}
145	
146	export function claim(_input: unknown): unknown {
147	  return undefined;
148	}
