// Insurance sum per item type, in G.
const INSURANCE_SUM_BY_TYPE: Record<Item["type"], number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};

const DEDUCTIBLE = 100;
const CAP_MULTIPLIER = 2;

export type ClaimItem = {
  type: Item["type"];
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type Damage = {
  itemType: Item["type"];
  amount: number;
};

export type ClaimInput = {
  policy: { items: ClaimItem[] };
  incident: { damages: Damage[] };
};

export type ClaimResult = {
  payout: number;
  remainingCap: number;
};

export function claim(input: ClaimInput): ClaimResult {
  const insuranceSum = input.policy.items.reduce(
    (sum, item) => sum + INSURANCE_SUM_BY_TYPE[item.type],
    0,
  );
  const cap = CAP_MULTIPLIER * insuranceSum;
  let payout = 0;
  for (const damage of input.incident.damages) {
    payout += Math.max(0, damage.amount - DEDUCTIBLE);
  }
  return { payout: Math.floor(payout), remainingCap: cap - payout };
}
